import requests
import json

class RabbitMQConfigurator:
    def __init__(self, api_url, username, password):
        self.api_url = api_url
        self.auth = (username, password)
        self.headers = {'Content-Type': 'application/json'}

    def _make_request(self, method, endpoint, data=None):
        url = f"{self.api_url}{endpoint}"
        try:
            if method == 'GET':
                response = requests.get(url, auth=self.auth)
            elif method == 'PUT':
                response = requests.put(url, auth=self.auth, headers=self.headers, data=json.dumps(data))
            elif method == 'POST':
                response = requests.post(url, auth=self.auth, headers=self.headers, data=json.dumps(data))
            elif method == 'DELETE':
                response = requests.delete(url, auth=self.auth)
            else:
                raise ValueError(f"Unsupported HTTP method: {method}")

            response.raise_for_status()
            return response
        except requests.exceptions.RequestException as e:
            print(f"Error during {method} request to {url}: {e}")
            if hasattr(e, 'response') and e.response is not None:
                print(f"Response status: {e.response.status_code}")
                print(f"Response body: {e.response.text}")
            return None

    def create_vhost(self, vhost_name):
        print(f"Attempting to create vhost: {vhost_name}")
        response = self._make_request('PUT', f'/api/vhosts/{vhost_name}')
        if response and response.status_code in [201, 204]:
            print(f"Vhost '{vhost_name}' created or already exists.")
            return True
        else:
            print(f"Failed to create vhost '{vhost_name}'.")
            return False

    def delete_vhost(self, vhost_name):
        print(f"Attempting to delete vhost: {vhost_name}")
        response = self._make_request('DELETE', f'/api/vhosts/{vhost_name}')
        if response and response.status_code == 204:
            print(f"Vhost '{vhost_name}' deleted.")
            return True
        else:
            print(f"Failed to delete vhost '{vhost_name}'.")
            return False

    def create_user(self, username, password, tags=''):
        print(f"Attempting to create user: {username}")
        data = {
            "password": password,
            "tags": tags
        }
        response = self._make_request('PUT', f'/api/users/{username}', data=data)
        if response and response.status_code in [201, 204]:
            print(f"User '{username}' created or already exists.")
            return True
        else:
            print(f"Failed to create user '{username}'.")
            return False

    def delete_user(self, username):
        print(f"Attempting to delete user: {username}")
        response = self._make_request('DELETE', f'/api/users/{username}')
        if response and response.status_code == 204:
            print(f"User '{username}' deleted.")
            return True
        else:
            print(f"Failed to delete user '{username}'.")
            return False

    def set_permissions(self, vhost_name, username, configure_regex='.*', write_regex='.*', read_regex='.*'):
        print(f"Attempting to set permissions for user '{username}' on vhost '{vhost_name}'")
        data = {
            "configure": configure_regex,
            "write": write_regex,
            "read": read_regex
        }
        response = self._make_request('PUT', f'/api/permissions/{vhost_name}/{username}', data=data)
        if response and response.status_code in [201, 204]:
            print(f"Permissions set for user '{username}' on vhost '{vhost_name}'.")
            return True
        else:
            print(f"Failed to set permissions for user '{username}' on vhost '{vhost_name}'.")
            return False

    def delete_permissions(self, vhost_name, username):
        print(f"Attempting to delete permissions for user '{username}' on vhost '{vhost_name}'")
        response = self._make_request('DELETE', f'/api/permissions/{vhost_name}/{username}')
        if response and response.status_code == 204:
            print(f"Permissions deleted for user '{username}' on vhost '{vhost_name}'.")
            return True
        else:
            print(f"Failed to delete permissions for user '{username}' on vhost '{vhost_name}'.")
            return False

